import{_ as e,o as s,c as n,ae as o}from"./chunks/framework.C7FLYIpo.js";const u=JSON.parse('{"title":"컨텍스트","description":"컨텍스트: 모델이 보는 것, 빌드 방법, 검사 방법","frontmatter":{"title":"컨텍스트","description":"컨텍스트: 모델이 보는 것, 빌드 방법, 검사 방법"},"headers":[],"relativePath":"concepts/context.md","filePath":"concepts/context.md","lastUpdated":null}'),t={name:"concepts/context.md"};function c(l,a,p,i,d,r){return s(),n("div",null,[...a[0]||(a[0]=[o(`<h1 id="컨텍스트" tabindex="-1">컨텍스트 <a class="header-anchor" href="#컨텍스트" aria-label="Permalink to &quot;컨텍스트&quot;">​</a></h1><p>&quot;컨텍스트&quot;는 <strong>OpenClaw가 실행을 위해 모델에 보내는 모든 것</strong>입니다. 모델의 <strong>컨텍스트 윈도우</strong> (토큰 한도)에 의해 제한됩니다.</p><p>초보자 멘탈 모델:</p><ul><li><strong>시스템 프롬프트</strong> (OpenClaw 빌드): 규칙, 도구, 스킬 목록, 시간/런타임, 주입된 워크스페이스 파일.</li><li><strong>대화 히스토리</strong>: 이 세션의 여러분 메시지 + 어시스턴트 메시지.</li><li><strong>도구 호출/결과 + 첨부파일</strong>: 명령 출력, 파일 읽기, 이미지/오디오 등.</li></ul><p>컨텍스트는 &quot;메모리&quot;와 <em>같지 않습니다</em>: 메모리는 디스크에 저장되어 나중에 다시 로드될 수 있지만; 컨텍스트는 모델의 현재 윈도우 내에 있는 것입니다.</p><h2 id="빠른-시작-컨텍스트-검사" tabindex="-1">빠른 시작 (컨텍스트 검사) <a class="header-anchor" href="#빠른-시작-컨텍스트-검사" aria-label="Permalink to &quot;빠른 시작 (컨텍스트 검사)&quot;">​</a></h2><ul><li><code>/status</code> → 빠른 &quot;내 윈도우가 얼마나 찼나요?&quot; 뷰 + 세션 설정.</li><li><code>/context list</code> → 주입된 것 + 대략적인 크기 (파일당 + 합계).</li><li><code>/context detail</code> → 더 깊은 분석: 파일당, 도구 스키마 크기당, 스킬 항목 크기당, 시스템 프롬프트 크기.</li><li><code>/usage tokens</code> → 일반 응답에 응답당 사용 풋터 추가.</li><li><code>/compact</code> → 윈도우 공간을 확보하기 위해 오래된 히스토리를 컴팩트 항목으로 요약.</li></ul><p>참조: <a href="/openclaw-docs-ko/tools/slash-commands">슬래시 명령어</a>, <a href="/openclaw-docs-ko/reference/token-use">토큰 사용 및 비용</a>, <a href="/openclaw-docs-ko/concepts/compaction">컴팩션</a>.</p><h2 id="출력-예시" tabindex="-1">출력 예시 <a class="header-anchor" href="#출력-예시" aria-label="Permalink to &quot;출력 예시&quot;">​</a></h2><p>값은 모델, 프로바이더, 도구 정책, 워크스페이스 내용에 따라 다릅니다.</p><h3 id="context-list" tabindex="-1"><code>/context list</code> <a class="header-anchor" href="#context-list" aria-label="Permalink to &quot;\`/context list\`&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>🧠 Context breakdown</span></span>
<span class="line"><span>Workspace: &amp;lt;workspaceDir&amp;gt;</span></span>
<span class="line"><span>Bootstrap max/file: 20,000 chars</span></span>
<span class="line"><span>Sandbox: mode=non-main sandboxed=false</span></span>
<span class="line"><span>System prompt (run): 38,412 chars (~9,603 tok) (Project Context 23,901 chars (~5,976 tok))</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Injected workspace files:</span></span>
<span class="line"><span>- AGENTS.md: OK | raw 1,742 chars (~436 tok) | injected 1,742 chars (~436 tok)</span></span>
<span class="line"><span>- SOUL.md: OK | raw 912 chars (~228 tok) | injected 912 chars (~228 tok)</span></span>
<span class="line"><span>- TOOLS.md: TRUNCATED | raw 54,210 chars (~13,553 tok) | injected 20,962 chars (~5,241 tok)</span></span>
<span class="line"><span>- IDENTITY.md: OK | raw 211 chars (~53 tok) | injected 211 chars (~53 tok)</span></span>
<span class="line"><span>- USER.md: OK | raw 388 chars (~97 tok) | injected 388 chars (~97 tok)</span></span>
<span class="line"><span>- HEARTBEAT.md: MISSING | raw 0 | injected 0</span></span>
<span class="line"><span>- BOOTSTRAP.md: OK | raw 0 chars (~0 tok) | injected 0 chars (~0 tok)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Skills list (system prompt text): 2,184 chars (~546 tok) (12 skills)</span></span>
<span class="line"><span>Tools: read, edit, write, exec, process, browser, message, sessions_send, …</span></span>
<span class="line"><span>Tool list (system prompt text): 1,032 chars (~258 tok)</span></span>
<span class="line"><span>Tool schemas (JSON): 31,988 chars (~7,997 tok) (counts toward context; not shown as text)</span></span>
<span class="line"><span>Tools: (same as above)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Session tokens (cached): 14,250 total / ctx=32,000</span></span></code></pre></div><h3 id="context-detail" tabindex="-1"><code>/context detail</code> <a class="header-anchor" href="#context-detail" aria-label="Permalink to &quot;\`/context detail\`&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>🧠 Context breakdown (detailed)</span></span>
<span class="line"><span>…</span></span>
<span class="line"><span>Top skills (prompt entry size):</span></span>
<span class="line"><span>- frontend-design: 412 chars (~103 tok)</span></span>
<span class="line"><span>- oracle: 401 chars (~101 tok)</span></span>
<span class="line"><span>… (+10 more skills)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Top tools (schema size):</span></span>
<span class="line"><span>- browser: 9,812 chars (~2,453 tok)</span></span>
<span class="line"><span>- exec: 6,240 chars (~1,560 tok)</span></span>
<span class="line"><span>… (+N more tools)</span></span></code></pre></div><h2 id="컨텍스트-윈도우에-포함되는-것" tabindex="-1">컨텍스트 윈도우에 포함되는 것 <a class="header-anchor" href="#컨텍스트-윈도우에-포함되는-것" aria-label="Permalink to &quot;컨텍스트 윈도우에 포함되는 것&quot;">​</a></h2><p>모델이 받는 모든 것이 포함됩니다:</p><ul><li>시스템 프롬프트 (모든 섹션).</li><li>대화 히스토리.</li><li>도구 호출 + 도구 결과.</li><li>첨부파일/트랜스크립트 (이미지/오디오/파일).</li><li>컴팩션 요약 및 프루닝 아티팩트.</li><li>프로바이더 &quot;래퍼&quot; 또는 숨겨진 헤더 (보이지 않지만, 여전히 계산됨).</li></ul><h2 id="openclaw가-시스템-프롬프트를-빌드하는-방법" tabindex="-1">OpenClaw가 시스템 프롬프트를 빌드하는 방법 <a class="header-anchor" href="#openclaw가-시스템-프롬프트를-빌드하는-방법" aria-label="Permalink to &quot;OpenClaw가 시스템 프롬프트를 빌드하는 방법&quot;">​</a></h2><p>시스템 프롬프트는 <strong>OpenClaw 소유</strong>이며 각 실행마다 재빌드됩니다. 다음을 포함합니다:</p><ul><li>도구 목록 + 간단한 설명.</li><li>스킬 목록 (메타데이터만; 아래 참조).</li><li>워크스페이스 위치.</li><li>시간 (UTC + 구성된 경우 변환된 사용자 시간).</li><li>런타임 메타데이터 (호스트/OS/모델/사고).</li><li><strong>Project Context</strong> 아래 주입된 워크스페이스 부트스트랩 파일.</li></ul><p>전체 분석: <a href="/openclaw-docs-ko/concepts/system-prompt">시스템 프롬프트</a>.</p><h2 id="주입된-워크스페이스-파일-project-context" tabindex="-1">주입된 워크스페이스 파일 (Project Context) <a class="header-anchor" href="#주입된-워크스페이스-파일-project-context" aria-label="Permalink to &quot;주입된 워크스페이스 파일 (Project Context)&quot;">​</a></h2><p>기본적으로 OpenClaw는 다음과 같은 고정된 워크스페이스 파일 세트를 주입합니다 (있는 경우):</p><ul><li><code>AGENTS.md</code></li><li><code>SOUL.md</code></li><li><code>TOOLS.md</code></li><li><code>IDENTITY.md</code></li><li><code>USER.md</code></li><li><code>HEARTBEAT.md</code></li><li><code>BOOTSTRAP.md</code> (최초 실행만)</li></ul><p>대용량 파일은 <code>agents.defaults.bootstrapMaxChars</code> (기본값 <code>20000</code>자)를 사용하여 파일당 잘립니다. OpenClaw는 또한 <code>agents.defaults.bootstrapTotalMaxChars</code> (기본값 <code>150000</code>자)로 파일 전체에 걸쳐 총 부트스트랩 주입 상한을 적용합니다. <code>/context</code>는 <strong>원본 대 주입</strong> 크기와 잘림 발생 여부를 표시합니다.</p><p>잘림이 발생하면 런타임은 Project Context 아래에 인프롬프트 경고 블록을 주입할 수 있습니다. <code>agents.defaults.bootstrapPromptTruncationWarning</code> (<code>off</code>, <code>once</code>, <code>always</code>; 기본값 <code>once</code>)으로 구성하십시오.</p><h2 id="스킬-주입됨-vs-요청-시-로드됨" tabindex="-1">스킬: 주입됨 vs 요청 시 로드됨 <a class="header-anchor" href="#스킬-주입됨-vs-요청-시-로드됨" aria-label="Permalink to &quot;스킬: 주입됨 vs 요청 시 로드됨&quot;">​</a></h2><p>시스템 프롬프트에는 컴팩트한 <strong>스킬 목록</strong> (이름 + 설명 + 위치)이 포함됩니다. 이 목록에는 실제 오버헤드가 있습니다.</p><p>스킬 지침은 기본적으로 포함되지 <em>않습니다</em>. 모델은 필요할 때만 스킬의 <code>SKILL.md</code>를 <code>read</code>할 것으로 기대됩니다.</p><h2 id="도구-두-가지-비용이-있습니다" tabindex="-1">도구: 두 가지 비용이 있습니다 <a class="header-anchor" href="#도구-두-가지-비용이-있습니다" aria-label="Permalink to &quot;도구: 두 가지 비용이 있습니다&quot;">​</a></h2><p>도구는 두 가지 방법으로 컨텍스트에 영향을 미칩니다:</p><ol><li>시스템 프롬프트의 <strong>도구 목록 텍스트</strong> (&quot;도구&quot; 로 보이는 것).</li><li><strong>도구 스키마</strong> (JSON). 이들은 모델이 도구를 호출할 수 있도록 모델에 전송됩니다. 일반 텍스트로 보이지 않더라도 컨텍스트를 차지합니다.</li></ol><p><code>/context detail</code>은 가장 큰 도구 스키마를 분석하여 무엇이 지배적인지 볼 수 있게 합니다.</p><h2 id="커맨드-지시어-및-인라인-단축키" tabindex="-1">커맨드, 지시어, 및 &quot;인라인 단축키&quot; <a class="header-anchor" href="#커맨드-지시어-및-인라인-단축키" aria-label="Permalink to &quot;커맨드, 지시어, 및 &quot;인라인 단축키&quot;&quot;">​</a></h2><p>슬래시 커맨드는 게이트웨이에서 처리됩니다. 몇 가지 다른 동작이 있습니다:</p><ul><li><strong>독립 실행 커맨드</strong>: <code>/...</code>만 있는 메시지는 커맨드로 실행됩니다.</li><li><strong>지시어</strong>: <code>/think</code>, <code>/verbose</code>, <code>/reasoning</code>, <code>/elevated</code>, <code>/model</code>, <code>/queue</code>는 모델이 메시지를 보기 전에 제거됩니다. <ul><li>지시어만 있는 메시지는 세션 설정을 영속화합니다.</li><li>일반 메시지의 인라인 지시어는 메시지당 힌트로 작동합니다.</li></ul></li><li><strong>인라인 단축키</strong> (허용된 발신자만): 일반 메시지 내의 특정 <code>/...</code> 토큰은 즉시 실행될 수 있으며 (예: &quot;hey /status&quot;), 모델이 나머지 텍스트를 보기 전에 제거됩니다.</li></ul><p>세부사항: <a href="/openclaw-docs-ko/tools/slash-commands">슬래시 커맨드</a>.</p><h2 id="세션-컴팩션-프루닝-무엇이-영속화되는지" tabindex="-1">세션, 컴팩션, 프루닝 (무엇이 영속화되는지) <a class="header-anchor" href="#세션-컴팩션-프루닝-무엇이-영속화되는지" aria-label="Permalink to &quot;세션, 컴팩션, 프루닝 (무엇이 영속화되는지)&quot;">​</a></h2><p>메시지 간에 무엇이 영속화되는지는 메커니즘에 따라 다릅니다:</p><ul><li><strong>일반 히스토리</strong>는 정책에 따라 컴팩션/프루닝될 때까지 세션 트랜스크립트에 영속화됩니다.</li><li><strong>컴팩션</strong>은 트랜스크립트에 요약을 영속화하고 최근 메시지를 그대로 유지합니다.</li><li><strong>프루닝</strong>은 실행에 대한 <em>인메모리</em> 프롬프트에서 오래된 도구 결과를 제거하지만, 트랜스크립트를 다시 쓰지 않습니다.</li></ul><p>문서: <a href="/openclaw-docs-ko/concepts/session">세션</a>, <a href="/openclaw-docs-ko/concepts/compaction">컴팩션</a>, <a href="/openclaw-docs-ko/concepts/session-pruning">세션 프루닝</a>.</p><p>기본적으로 OpenClaw는 조립 및 컴팩션에 내장 <code>legacy</code> 컨텍스트 엔진을 사용합니다. <code>kind: &quot;context-engine&quot;</code>을 제공하는 플러그인을 설치하고 <code>plugins.slots.contextEngine</code>으로 선택하면 OpenClaw는 해당 엔진에 컨텍스트 조립, <code>/compact</code>, 관련 서브에이전트 컨텍스트 생명주기 후크를 위임합니다. <code>ownsCompaction: false</code>는 레거시 엔진으로 자동 폴백하지 않습니다; 활성 엔진은 여전히 <code>compact()</code>를 올바르게 구현해야 합니다. 전체 플러그 가능한 인터페이스, 생명주기 후크, 구성은 <a href="/openclaw-docs-ko/concepts/context-engine">컨텍스트 엔진</a>을 참조하십시오.</p><h2 id="context가-실제로-보고하는-것" tabindex="-1"><code>/context</code>가 실제로 보고하는 것 <a class="header-anchor" href="#context가-실제로-보고하는-것" aria-label="Permalink to &quot;\`/context\`가 실제로 보고하는 것&quot;">​</a></h2><p><code>/context</code>는 가능한 경우 최신 <strong>실행 빌드</strong> 시스템 프롬프트 보고서를 선호합니다:</p><ul><li><code>System prompt (run)</code> = 마지막 임베디드 (도구 사용 가능) 실행에서 캡처되고 세션 저장소에 영속화됨.</li><li><code>System prompt (estimate)</code> = 실행 보고서가 없을 때 (또는 보고서를 생성하지 않는 CLI 백엔드를 통해 실행할 때) 즉석에서 계산됨.</li></ul><p>어느 쪽이든 크기 및 최상위 기여자를 보고합니다; 전체 시스템 프롬프트 또는 도구 스키마를 덤프하지 않습니다.</p><h2 id="관련-항목" tabindex="-1">관련 항목 <a class="header-anchor" href="#관련-항목" aria-label="Permalink to &quot;관련 항목&quot;">​</a></h2><ul><li><a href="/openclaw-docs-ko/concepts/context-engine">컨텍스트 엔진</a> — 플러그인을 통한 사용자 정의 컨텍스트 주입</li><li><a href="/openclaw-docs-ko/concepts/compaction">컴팩션</a> — 긴 대화 요약</li><li><a href="/openclaw-docs-ko/concepts/system-prompt">시스템 프롬프트</a> — 시스템 프롬프트 빌드 방법</li><li><a href="/openclaw-docs-ko/concepts/agent-loop">에이전트 루프</a> — 전체 에이전트 실행 사이클</li></ul>`,48)])])}const m=e(t,[["render",c]]);export{u as __pageData,m as default};
